import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { adminGuard } from './core/guards/admin.guard';
import { FlowRoute } from './flow-meta';

// `data.flow` is the single source of truth for the user-flow graph AND the runtime navbar.
// The colossus flow-graph extractor projects it directly (zero heuristics). Authoring rules
// + lint: docs/flow-graph-convention.md + platform/flowgraph-static/verify/flow-lint.mjs.
//
// DEEP-LINKABLE STATE — every navigable UI state a user could leave feedback on must be
// reachable by URL. Detail panes use `/:id` child routes; the admin create/edit modal uses
// `?modal=new` / `?modal=edit&id=` query params restored on init.
//
// NOTE: Angular `data` is NOT inherited by child routes — `flow` is repeated on children.
export const routes: Routes = ([
  { path: '', redirectTo: 'catalog', pathMatch: 'full' },
  {
    path: 'login',
    loadComponent: () =>
      import('./features/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { flowId: 'login', node: 'login', entry: true, edgesTo: ['catalog', 'signup'], label: 'Login' } },
  },
  {
    path: 'signup',
    loadComponent: () =>
      import('./features/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { flowId: 'signup', node: 'signup', entry: true, edgesTo: ['catalog', 'login'], label: 'Sign up' } },
  },
  {
    path: 'catalog',
    loadComponent: () =>
      import('./features/catalog/catalog-list.component').then((m) => m.CatalogListComponent),
    canActivate: [authGuard],
    data: { flow: { flowId: 'catalog', node: 'catalog', showInNavbar: true, label: 'Shop', scope: 'all', edgesTo: ['catalog-detail', 'cart'] } },
  },
  {
    path: 'catalog/:id',
    loadComponent: () =>
      import('./features/catalog/catalog-detail.component').then((m) => m.CatalogDetailComponent),
    canActivate: [authGuard],
    data: { flow: { flowId: 'catalog-detail', node: 'catalog-detail', label: 'Product', scope: 'all', edgesTo: ['catalog', 'cart'] } },
  },
  {
    path: 'cart',
    loadComponent: () =>
      import('./features/cart/cart.component').then((m) => m.CartComponent),
    canActivate: [authGuard],
    data: { flow: { flowId: 'cart', node: 'cart', showInNavbar: true, label: 'Cart', scope: 'all', edgesTo: ['catalog', 'checkout'] } },
  },
  {
    path: 'checkout',
    loadComponent: () =>
      import('./features/checkout/checkout.component').then((m) => m.CheckoutComponent),
    canActivate: [authGuard],
    data: { flow: { flowId: 'checkout', node: 'checkout', label: 'Checkout', scope: 'all', edgesTo: ['orders', 'cart'] } },
  },
  {
    path: 'orders',
    loadComponent: () =>
      import('./features/orders/orders.component').then((m) => m.OrdersComponent),
    canActivate: [authGuard],
    data: { flow: { flowId: 'orders', node: 'orders', showInNavbar: true, label: 'Orders', scope: 'all', edgesTo: ['order-detail', 'catalog'] } },
  },
  {
    path: 'orders/:id',
    loadComponent: () =>
      import('./features/orders/order-detail.component').then((m) => m.OrderDetailComponent),
    canActivate: [authGuard],
    data: { flow: { flowId: 'order-detail', node: 'order-detail', label: 'Order detail', scope: 'all', edgesTo: ['orders'] } },
  },
  {
    path: 'admin/products',
    loadComponent: () =>
      import('./features/admin/admin-products.component').then((m) => m.AdminProductsComponent),
    canActivate: [adminGuard],
    data: { flow: { flowId: 'admin-products', node: 'admin-products', showInNavbar: true, label: 'Admin', scope: 'admin', edgesTo: ['catalog'] } },
  },
  { path: '**', redirectTo: 'catalog' },
] satisfies FlowRoute[]) as Routes;
