import { Component, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterOutlet, RouterLink, RouterLinkActive } from '@angular/router';
import { AuthService } from './core/services/auth.service';
import { CartService } from './core/services/cart.service';

interface NavItem {
  path: string;
  label: string;
  icon: string;
  scope: 'all' | 'admin';
  showCartBadge?: boolean;
}

// Mirrors the `showInNavbar` routes in app.routes.ts (which remain the flow-graph source of truth).
const NAV_ITEMS: NavItem[] = [
  { path: '/catalog', label: 'Shop', icon: '🛍️', scope: 'all' },
  { path: '/cart', label: 'Cart', icon: '🛒', scope: 'all', showCartBadge: true },
  { path: '/orders', label: 'Orders', icon: '📦', scope: 'all' },
  { path: '/admin/products', label: 'Admin', icon: '⚙️', scope: 'admin' },
];

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, RouterOutlet, RouterLink, RouterLinkActive],
  templateUrl: './app.component.html',
})
export class AppComponent {
  readonly isLoggedIn = this.auth.isLoggedIn;
  readonly cartCount = this.cart.count;

  readonly navItems = computed<NavItem[]>(() =>
    NAV_ITEMS.filter((item) => item.scope === 'all' || this.auth.isAdmin()),
  );

  constructor(
    private auth: AuthService,
    private cart: CartService,
  ) {}

  logout(): void {
    this.auth.logout();
  }
}
